/**
 * @param {number} n
 * @param {number[]} prices
 * @param {number[][]} roads
 * @return {number[]}
 */
function solve(n, prices, roads) {
    // Step 1: Calculate minimum cost to travel from any node to any other node (Empty hands)
    // We use Dijkstra's algorithm for this. The cost is simply 'cost_i'.
    // Since the graph is undirected, we build an adjacency list where edge weights are 'cost'.
    const adjCost = Array(n).fill(0).map(() => []);
    for (const [u, v, cost, tax] of roads) {
        // Undirected graph for empty hands travel
        adjCost[u].push({ node: v, weight: cost });
        adjCost[v].push({ node: u, weight: cost });
    }

    // distEmpty[i][j] = shortest path cost from i to j with empty hands
    // Since the roads are bidirectional and weights are non-negative, Dijkstra works.
    // We need All-Pairs Shortest Path (APSP) for the empty hands travel.
    // Since N is up to 1000, running Dijkstra N times is feasible (O(N * (E + N log N))).
    // E is up to 2000, N*E approx 2*10^6. N*logN approx 10000. This is fine.

    const distEmpty = Array(n).fill(0).map(() => Array(n).fill(Infinity));

    const dijkstra = (startNode) => {
        const distances = Array(n).fill(Infinity);
        distances[startNode] = 0;
        // Priority Queue: [distance, node]
        const pq = [[0, startNode]]; // Min-heap simulation using array sort/splice for simplicity given constraints, though a proper heap is better for strict efficiency.

        while (pq.length > 0) {
            // Simple min-heap extraction: O(K) where K is pq size. Total complexity suffers slightly.
            pq.sort((a, b) => a[0] - b[0]);
            const [d, u] = pq.shift();

            if (d > distances[u]) continue;

            for (const edge of adjCost[u]) {
                const v = edge.node;
                const weight = edge.weight;
                if (distances[u] + weight < distances[v]) {
                    distances[v] = distances[u] + weight;
                    pq.push([distances[v], v]);
                }
            }
        }
        return distances;
    };

    for (let i = 0; i < n; i++) {
        distEmpty[i] = dijkstra(i);
    }

    // Step 2: Calculate minimum cost to travel from any node to any other node (Carrying apples)
    // The cost is 'cost_i * tax_i'. This is also an APSP problem.
    const adjTaxed = Array(n).fill(0).map(() => []);
    for (const [u, v, cost, tax] of roads) {
        const taxedCost = cost * tax;
        // Undirected graph for carrying apples travel
        adjTaxed[u].push({ node: v, weight: taxedCost });
        adjTaxed[v].push({ node: u, weight: taxedCost });
    }

    const distTaxed = Array(n).fill(0).map(() => Array(n).fill(Infinity));

    const dijkstraTaxed = (startNode) => {
        const distances = Array(n).fill(Infinity);
        distances[startNode] = 0;
        // Priority Queue: [distance, node]
        const pq = [[0, startNode]];

        while (pq.length > 0) {
            pq.sort((a, b) => a[0] - b[0]);
            const [d, u] = pq.shift();

            if (d > distances[u]) continue;

            for (const edge of adjTaxed[u]) {
                const v = edge.node;
                const weight = edge.weight;
                if (distances[u] + weight < distances[v]) {
                    distances[v] = distances[u] + weight;
                    pq.push([distances[v], v]);
                }
            }
        }
        return distances;
    };

    for (let i = 0; i < n; i++) {
        distTaxed[i] = dijkstraTaxed(i);
    }

    // Step 3: Calculate the final answer for each store i
    const ans = Array(n).fill(0);

    for (let i = 0; i < n; i++) {
        // Option 1: Buy at store i directly
        let minCost = prices[i];

        // Option 2: Travel to store j (empty hands), buy at j, travel back to i (carrying apples)
        // Total cost = Cost(i -> j empty) + Price[j] + Cost(j -> i taxed)
        for (let j = 0; j < n; j++) {
            if (i === j) continue;

            const costEmpty_i_to_j = distEmpty[i][j];
            const costTaxed_j_to_i = distTaxed[j][i];

            if (costEmpty_i_to_j !== Infinity && costTaxed_j_to_i !== Infinity) {
                // Total cost = Travel cost (Empty) + Purchase price + Travel cost (Taxed)
                // Note: The problem statement implies the return trip path from j to i must use the tax multiplier based on the edges traversed.
                // The cost calculated in distTaxed[j][i] already covers the return path cost.
                // Total Cost = (Min Empty Cost i->j) + prices[j] + (Min Taxed Cost j->i)
                const currentTotalCost = costEmpty_i_to_j + prices[j] + costTaxed_j_to_i;
                if (currentTotalCost < minCost) {
                    minCost = currentTotalCost;
                }
            }
        }
        ans[i] = minCost;
    }

    return ans;
}

